26	func (s *CollectibleService) Create(ctx context.Context, req dto.CreateCollectibleRequest, sellerID uuid.UUID) (*model.Collectible, error) {
27		currency := req.Currency
28		if currency == "" {
29			currency = "USD"
30		}
31	
32		tokenID := req.TokenID
33		chainID := req.ChainID
34		if req.ContractAddress != "" {
35			if tokenID == "" || chainID == 0 {
36				return nil, fmt.Errorf("%w: contract_address requires chain_id and token_id", dto.ErrValidation)
37			}
38		} else {
39			if tokenID == "" {
40				tokenID = uuid.New().String()
41			}
42			if chainID == 0 {
43				chainID = 1
44			}
45		}
46	
47		c := &model.Collectible{
48			SellerID:        sellerID,
49			Title:           req.Title,
50			Description:     req.Description,
51			ContractAddress: req.ContractAddress,
52			ChainID:         chainID,
53			TokenID:         tokenID,
54			MetadataURI:     req.MetadataURI,
55			ImageURL:        req.ImageURL,
56			PriceCents:      req.PriceCents,
57			Currency:        currency,
58		}
59	
60		if err := s.collectibleStore.Create(ctx, c); err != nil {
61			if strings.Contains(err.Error(), "idx_collectibles_identity") || strings.Contains(err.Error(), "duplicate key") {
62				return nil, fmt.Errorf("%w: a collectible with this contract_address, chain_id, and token_id already exists", dto.ErrConflict)
63			}
64			return nil, fmt.Errorf("create collectible: %w", err)
65		}
66		s.invalidateCache()
67		return c, nil
68	}
