70	// GetByID returns a collectible. Hidden collectibles are only visible to admin/compliance roles.
71	func (s *CollectibleService) GetByID(ctx context.Context, id uuid.UUID, viewerRoles []string) (*model.Collectible, error) {
72		cacheKey := "collectible:" + id.String()
73		if cached, ok := s.cache.Get(cacheKey); ok {
74			c := cached.(*model.Collectible)
75			if c.Status == "hidden" && !hasAdminOrCompliance(viewerRoles) {
76				return nil, dto.ErrNotFound
77			}
78			return c, nil
79		}
80	
81		c, err := s.collectibleStore.GetByID(ctx, id)
82		if err != nil {
83			return nil, err
84		}
85		if c == nil {
86			return nil, dto.ErrNotFound
87		}
88	
89		// Hidden collectibles only visible to admin/compliance
90		if c.Status == "hidden" && !hasAdminOrCompliance(viewerRoles) {
91			return nil, dto.ErrNotFound
92		}
93	
94		s.cache.Set(cacheKey, c, 2*time.Minute)
95	
96		// Emit item_view event and increment view count async
97		go func() {
98			_ = s.collectibleStore.IncrementViewCount(context.Background(), id)
99		}()
100	
101		return c, nil
102	}
