104	// EmitViewEvent emits an analytics event for viewing. Called separately to have access to userID.
105	func (s *CollectibleService) EmitViewEvent(ctx context.Context, userID *uuid.UUID, collectibleID uuid.UUID) {
106		if s.analyticsStore == nil {
107			return
108		}
109		abVariant := resolveABVariant(s.analyticsStore, userID)
110		go func() {
111			_ = s.analyticsStore.RecordEvent(context.Background(), &model.AnalyticsEvent{
112				UserID:        userID,
113				EventType:     "item_view",
114				CollectibleID: &collectibleID,
115				SessionID:     "server",
116				ABVariant:     abVariant,
117			})
118		}()
119	}
