166	func (s *CollectibleService) Update(ctx context.Context, id uuid.UUID, req dto.UpdateCollectibleRequest, actorID uuid.UUID) (*model.Collectible, error) {
167		c, err := s.collectibleStore.GetByID(ctx, id)
168		if err != nil {
169			return nil, err
170		}
171		if c == nil {
172			return nil, dto.ErrNotFound
173		}
174		if c.SellerID != actorID {
175			return nil, dto.ErrForbidden
176		}
177	
178		if req.Title != nil {
179			c.Title = *req.Title
180		}
181		if req.Description != nil {
182			c.Description = *req.Description
183		}
184		if req.PriceCents != nil {
185			c.PriceCents = *req.PriceCents
186		}
187		if req.ImageURL != nil {
188			c.ImageURL = *req.ImageURL
189		}
190		if req.MetadataURI != nil {
191			c.MetadataURI = *req.MetadataURI
192		}
193	
194		if err := s.collectibleStore.Update(ctx, c); err != nil {
195			return nil, fmt.Errorf("update collectible: %w", err)
196		}
197		s.invalidateCache()
198		return c, nil
199	}
