15	type OrderService struct {
16		orderStore       *store.OrderStore
17		collectibleStore *store.CollectibleStore
18		notifService     *NotificationService
19		analyticsStore   *store.AnalyticsStore
20	}
21	
22	func NewOrderService(os *store.OrderStore, cs *store.CollectibleStore, ns *NotificationService, as *store.AnalyticsStore) *OrderService {
23		return &OrderService{orderStore: os, collectibleStore: cs, notifService: ns, analyticsStore: as}
24	}
25	
26	func (s *OrderService) Create(ctx context.Context, req dto.CreateOrderRequest, buyerID uuid.UUID, idempotencyKey string) (*model.Order, error) {
27		existing, err := s.orderStore.GetByIdempotencyKey(ctx, buyerID, idempotencyKey)
28		if err != nil {
29			return nil, fmt.Errorf("check idempotency: %w", err)
30		}
31		if existing != nil {
32			return existing, nil
33		}
34	
35		collectible, err := s.collectibleStore.GetByID(ctx, req.CollectibleID)
36		if err != nil {
37			return nil, fmt.Errorf("get collectible: %w", err)
38		}
39		if collectible == nil {
40			return nil, dto.ErrNotFound
41		}
42		if collectible.Status != "published" {
43			return nil, dto.ErrNotFound
44		}
45		if collectible.SellerID == buyerID {
46			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
47			return nil, fmt.Errorf("%w: cannot buy your own collectible", dto.ErrValidation)
48		}
49	
50		tx, err := s.orderStore.BeginTx(ctx)
51		if err != nil {
52			return nil, fmt.Errorf("begin tx: %w", err)
53		}
54		defer tx.Rollback(ctx)
55	
56		if err := s.orderStore.AcquireAdvisoryLock(ctx, tx, req.CollectibleID); err != nil {
57			return nil, fmt.Errorf("acquire lock: %w", err)
58		}
59	
60		hasActive, err := s.orderStore.HasActiveOrder(ctx, tx, req.CollectibleID)
61		if err != nil {
62			return nil, fmt.Errorf("check active orders: %w", err)
63		}
64		if hasActive {
65			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
66			return nil, dto.ErrOversold
67		}
68	
69		order := &model.Order{
70			IdempotencyKey:     idempotencyKey,
71			BuyerID:            buyerID,
72			CollectibleID:      req.CollectibleID,
73			SellerID:           collectible.SellerID,
74			Status:             model.OrderStatusPending,
75			PriceSnapshotCents: collectible.PriceCents,
76		}
77	
78		if err := s.orderStore.CreateInTx(ctx, tx, order); err != nil {
79			return nil, fmt.Errorf("create order: %w", err)
80		}
81	
82		transition := &model.OrderStateTransition{
83			OrderID:    order.ID,
84			FromStatus: "",
85			ToStatus:   model.OrderStatusPending,
86			ActorID:    buyerID,
87			Reason:     "order created",
88		}
89		if err := s.orderStore.RecordTransitionInTx(ctx, tx, transition); err != nil {
90			return nil, fmt.Errorf("record transition: %w", err)
91		}
92	
93		if err := tx.Commit(ctx); err != nil {
94			return nil, fmt.Errorf("commit: %w", err)
95		}
96	
97		// Emit analytics event
98		s.emitEvent(ctx, &buyerID, "order_created", &req.CollectibleID)
99	
100		return order, nil
101	}
102	
103	// GetByID with object-level authorization: only buyer or seller of the order can view it.
104	func (s *OrderService) GetByID(ctx context.Context, id uuid.UUID, actorID uuid.UUID) (*model.Order, error) {
105		order, err := s.orderStore.GetByID(ctx, id)
106		if err != nil {
107			return nil, err
108		}
109		if order == nil {
110			return nil, dto.ErrNotFound
111		}
112		if order.BuyerID != actorID && order.SellerID != actorID {
113			return nil, dto.ErrForbidden
114		}
115		return order, nil
116	}
117	
118	// TransitionStatus with object-level authorization.
119	// Confirm/Process/Complete: only the seller of THIS order.
120	// Cancel: only the buyer or seller of THIS order.
121	func (s *OrderService) TransitionStatus(ctx context.Context, orderID uuid.UUID, targetStatus model.OrderStatus, actorID uuid.UUID, reason string) (*model.Order, error) {
122		order, err := s.orderStore.GetByID(ctx, orderID)
123		if err != nil {
124			return nil, err
125		}
126		if order == nil {
127			return nil, dto.ErrNotFound
128		}
129	
130		// Object-level authorization
131		switch targetStatus {
132		case model.OrderStatusConfirmed, model.OrderStatusProcessing, model.OrderStatusCompleted:
133			if order.SellerID != actorID {
134				return nil, fmt.Errorf("%w: only the seller of this order can perform this action", dto.ErrForbidden)
135			}
136		case model.OrderStatusCancelled:
137			if order.BuyerID != actorID && order.SellerID != actorID {
138				return nil, fmt.Errorf("%w: only the buyer or seller of this order can cancel it", dto.ErrForbidden)
139			}
140		}
141	
142		if !order.Status.CanTransitionTo(targetStatus) {
143			return nil, fmt.Errorf("%w: cannot transition from %s to %s", dto.ErrInvalidTransition, order.Status, targetStatus)
144		}
145	
146		if targetStatus == model.OrderStatusCancelled {
147			if err := s.orderStore.Cancel(ctx, orderID, reason, actorID); err != nil {
148				return nil, fmt.Errorf("cancel order: %w", err)
149			}
150			s.emitEvent(ctx, &actorID, "order_cancelled", &order.CollectibleID)
151		} else {
152			if err := s.orderStore.UpdateStatus(ctx, orderID, targetStatus); err != nil {
153				return nil, fmt.Errorf("update status: %w", err)
154			}
155		}
156	
157		transition := &model.OrderStateTransition{
158			OrderID:    orderID,
159			FromStatus: order.Status,
160			ToStatus:   targetStatus,
161			ActorID:    actorID,
162			Reason:     reason,
163		}
164		if err := s.orderStore.RecordTransition(ctx, transition); err != nil {
165			return nil, fmt.Errorf("record transition: %w", err)
166		}
167	
168		// On completion, record an immutable transaction history entry for the
169		// collectible, representing the ownership transfer from seller to buyer.
170		if targetStatus == model.OrderStatusCompleted {
171			s.recordOwnershipTransfer(ctx, order)
172		}
173	
174		s.sendOrderNotification(ctx, order, targetStatus, reason)
175	
176		order.Status = targetStatus
177		return order, nil
178	}
179	
180	func (s *OrderService) sendOrderNotification(ctx context.Context, order *model.Order, status model.OrderStatus, reason string) {
181		if s.notifService == nil {
182			return
183		}
184	
185		slugMap := map[model.OrderStatus]string{
186			model.OrderStatusConfirmed:  "order_confirmed",
187			model.OrderStatusProcessing: "order_processing",
188			model.OrderStatusCompleted:  "order_completed",
189			model.OrderStatusCancelled:  "order_cancelled",
190		}
191	
192		slug, ok := slugMap[status]
193		if !ok {
194			return
195		}
196	
197		params := map[string]string{
198			"OrderID": order.ID.String(),
199			"Reason":  reason,
200		}
201		paramsJSON, _ := json.Marshal(params)
202	
203		go func() {
204			_ = s.notifService.Send(context.Background(), order.BuyerID, slug, paramsJSON)
205		}()
206	}
207	
208	// recordOwnershipTransfer appends an immutable record to collectible_tx_history
209	// when an order completes. The record captures the seller→buyer transfer using
210	// the collectible's on-chain identity. This is best-effort: a failure here does
211	// not roll back the order completion.
212	func (s *OrderService) recordOwnershipTransfer(ctx context.Context, order *model.Order) {
213		collectible, err := s.collectibleStore.GetByID(ctx, order.CollectibleID)
214		if err != nil || collectible == nil {
215			return
216		}
217	
218		fromAddr := collectible.ContractAddress
219		if fromAddr == "" {
220			fromAddr = order.SellerID.String()
221		}
222		toAddr := order.BuyerID.String()
223	
224		txHash := fmt.Sprintf("order:%s", order.ID.String())
225		blockNumber := order.PriceSnapshotCents // deterministic, non-zero value
226	
227		entry := &model.CollectibleTxHistory{
228			CollectibleID: order.CollectibleID,
229			TxHash:        txHash,
230			FromAddress:   fromAddr,
231			ToAddress:     toAddr,
232			BlockNumber:   blockNumber,
233			Timestamp:     time.Now(),
234		}
235	
236		// Best-effort: do not fail the order on tx history write failure.
237		_ = s.collectibleStore.RecordTxHistory(ctx, entry)
238	}
239	
240	// UpdateFulfillment with object-level authorization: only the seller of this order.
241	func (s *OrderService) UpdateFulfillment(ctx context.Context, orderID uuid.UUID, req dto.UpdateFulfillmentRequest, actorID uuid.UUID) error {
242		order, err := s.orderStore.GetByID(ctx, orderID)
243		if err != nil {
244			return err
245		}
246		if order == nil {
247			return dto.ErrNotFound
248		}
249		if order.SellerID != actorID {
250			return fmt.Errorf("%w: only the seller of this order can update fulfillment", dto.ErrForbidden)
251		}
252	
253		tracking, _ := json.Marshal(req)
254		return s.orderStore.UpdateFulfillment(ctx, orderID, tracking)
255	}
256	
257	func (s *OrderService) ListByBuyer(ctx context.Context, buyerID uuid.UUID, page, pageSize int) ([]model.Order, int, error) {
258		return s.orderStore.ListByBuyer(ctx, buyerID, page, pageSize)
259	}
260	
261	func (s *OrderService) ListBySeller(ctx context.Context, sellerID uuid.UUID, page, pageSize int) ([]model.Order, int, error) {
262		return s.orderStore.ListBySeller(ctx, sellerID, page, pageSize)
263	}
264	
265	func (s *OrderService) CountOpenByBuyer(ctx context.Context, buyerID uuid.UUID) (int, error) {
266		return s.orderStore.CountOpenByBuyer(ctx, buyerID)
267	}
268	
269	func (s *OrderService) emitEvent(ctx context.Context, userID *uuid.UUID, eventType string, collectibleID *uuid.UUID) {
270		if s.analyticsStore == nil {
