2	CREATE TABLE audit_logs (
3	    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
4	    actor_id UUID REFERENCES users(id),
5	    action VARCHAR(80) NOT NULL,
6	    resource_type VARCHAR(40) NOT NULL,
