122	func (s *CollectibleService) List(ctx context.Context, status string, page, pageSize int, viewerRoles []string, userID *uuid.UUID) ([]model.Collectible, int, error) {
123		// Non-admin/compliance users can ONLY see published
124		if !hasAdminOrCompliance(viewerRoles) {
125			status = "published"
126		}
127	
128		cacheKey := fmt.Sprintf("collectibles:%s:%d:%d", status, page, pageSize)
129		if cached, ok := s.cache.Get(cacheKey); ok {
130			result := cached.(*cachedList)
131			return result.items, result.total, nil
132		}
133	
134		items, total, err := s.collectibleStore.List(ctx, status, page, pageSize)
135		if err != nil {
136			return nil, 0, err
137		}
138	
139		s.cache.Set(cacheKey, &cachedList{items: items, total: total}, 30*time.Second)
140	
141		// Emit catalog_view event async with A/B variant tagging
142		if s.analyticsStore != nil {
143			abVariant := resolveABVariant(s.analyticsStore, userID)
144			go func() {
