1	import { useParams, useNavigate } from 'react-router-dom';
2	import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
3	import { getCollectible } from '../api/collectibles';
4	import { createOrder } from '../api/orders';
5	import { useAuthStore } from '../store/authStore';
6	import { formatCents, formatDate } from '../utils/formatters';
7	import { useState } from 'react';
8	
9	export function CollectiblePage() {
10	  const { id } = useParams<{ id: string }>();
11	  const navigate = useNavigate();
12	  const { hasRole, user } = useAuthStore();
13	  const queryClient = useQueryClient();
14	  const [orderError, setOrderError] = useState('');
15	
16	  const { data, isLoading } = useQuery({
17	    queryKey: ['collectible', id],
18	    queryFn: () => getCollectible(id!).then((r) => r.data),
19	    enabled: !!id,
20	  });
21	
22	  const orderMutation = useMutation({
23	    mutationFn: () => {
24	      const idempotencyKey = crypto.randomUUID();
25	      return createOrder(id!, idempotencyKey);
26	    },
27	    onSuccess: (res) => {
28	      queryClient.invalidateQueries({ queryKey: ['orders'] });
29	      navigate(`/orders/${res.data.id}`);
30	    },
31	    onError: (err: any) => {
32	      setOrderError(err.response?.data?.error?.message || 'Failed to place order');
33	    },
34	  });
35	
36	  if (isLoading) return <p className="text-gray-500">Loading...</p>;
37	  if (!data) return <p className="text-gray-500">Collectible not found.</p>;
38	
39	  const { collectible, transaction_history } = data;
40	  const isOwner = collectible.seller_id === user?.id;
41	
42	  return (
43	    <div className="max-w-5xl mx-auto">
44	      <button onClick={() => navigate(-1)} className="text-sm text-primary-600 hover:underline mb-4 block">
45	        Back
46	      </button>
47	
48	      <div className="bg-white rounded-lg shadow-sm border overflow-hidden">
49	        <div className="md:flex">
50	          <div className="md:w-1/2 lg:w-2/5">
51	            {collectible.image_url ? (
52	              <img src={collectible.image_url} alt={collectible.title} className="w-full h-64 md:h-80 lg:h-96 object-cover" />
53	            ) : (
54	              <div className="w-full h-64 md:h-80 lg:h-96 bg-gray-100 flex items-center justify-center text-gray-400">
55	                No image
56	              </div>
57	            )}
58	          </div>
59	          <div className="p-4 md:p-6 lg:p-8 md:w-1/2 lg:w-3/5">
60	            <h1 className="text-xl md:text-2xl lg:text-3xl font-bold text-gray-900 mb-2">{collectible.title}</h1>
61	            <p className="text-2xl md:text-3xl font-bold text-primary-700 mb-4">
62	              {formatCents(collectible.price_cents, collectible.currency)}
63	            </p>
64	            <p className="text-gray-600 mb-6">{collectible.description}</p>
65	
66	            {(collectible.contract_address || collectible.chain_id || collectible.token_id) && (
67	              <div className="space-y-1 text-sm text-gray-500 mb-4">
68	                {collectible.contract_address && (
69	                  <p>Contract: <span className="font-mono">{collectible.contract_address}</span></p>
70	                )}
71	                {collectible.chain_id && <p>Chain ID: {collectible.chain_id}</p>}
72	                {collectible.token_id && <p>Token ID: <span className="font-mono">{collectible.token_id}</span></p>}
73	              </div>
74	            )}
75	
76	            <div className="text-xs text-gray-400 mb-4">
77	              <p>{collectible.view_count} views</p>
78	              <p>Listed {formatDate(collectible.created_at)}</p>
79	            </div>
80	
81	            {hasRole('buyer') && !isOwner && (
82	              <div>
83	                <button
84	                  onClick={() => orderMutation.mutate()}
85	                  disabled={orderMutation.isPending}
86	                  className="w-full bg-primary-600 text-white py-3 rounded font-medium hover:bg-primary-700 disabled:opacity-50"
87	                >
88	                  {orderMutation.isPending ? 'Placing Order...' : 'Place Order'}
89	                </button>
90	                {orderError && (
91	                  <p className="text-sm text-red-600 mt-2">{orderError}</p>
92	                )}
93	              </div>
94	            )}
95	
96	            {isOwner && (
97	              <button
98	                onClick={() => navigate(`/sell/${id}/edit`)}
99	                className="w-full bg-gray-100 text-gray-700 py-3 rounded font-medium hover:bg-gray-200"
100	              >
101	                Edit Listing
102	              </button>
103	            )}
104	          </div>
105	        </div>
106	      </div>
107	
108	      {/* Immutable Transaction History — always visible to sellers, visible to others when data exists */}
109	      {(isOwner || (transaction_history && transaction_history.length > 0)) && (
110	        <div className="mt-6 bg-white rounded-lg shadow-sm border p-4 md:p-6">
111	          <div className="flex items-center gap-2 mb-4">
112	            <h2 className="text-lg font-semibold">Transaction History</h2>
113	            <span className="text-xs bg-gray-100 text-gray-500 px-2 py-0.5 rounded-full">Immutable</span>
114	          </div>
115	          {transaction_history && transaction_history.length > 0 ? (
116	            <div className="overflow-x-auto">
117	              <table className="min-w-full text-sm">
118	                <thead>
119	                  <tr className="text-left text-xs text-gray-500 uppercase border-b">
120	                    <th className="pb-2 pr-4">Tx Hash</th>
121	                    <th className="pb-2 pr-4">From</th>
122	                    <th className="pb-2 pr-4">To</th>
123	                    <th className="pb-2 pr-4 hidden md:table-cell">Block</th>
124	                    <th className="pb-2">Date</th>
125	                  </tr>
126	                </thead>
127	                <tbody className="divide-y divide-gray-100">
128	                  {transaction_history.map((tx) => (
129	                    <tr key={tx.id} className="text-gray-700">
130	                      <td className="py-2 pr-4 font-mono text-xs">{tx.tx_hash.slice(0, 10)}...</td>
131	                      <td className="py-2 pr-4 font-mono text-xs">{tx.from_address.slice(0, 10)}...</td>
132	                      <td className="py-2 pr-4 font-mono text-xs">{tx.to_address.slice(0, 10)}...</td>
133	                      <td className="py-2 pr-4 text-xs hidden md:table-cell">{tx.block_number}</td>
134	                      <td className="py-2 text-xs text-gray-400">{formatDate(tx.timestamp)}</td>
135	                    </tr>
136	                  ))}
137	                </tbody>
138	              </table>
139	            </div>
140	          ) : (
141	            <p className="text-sm text-gray-400">No past sales recorded for this collectible yet.</p>
142	          )}
143	        </div>
144	      )}
145	    </div>
146	  );
147	}
